class Solution {
    constructor(k, nums) {
        this.k = k;
        this.minHeap = [];

        // Insert each number and maintain heap of size k
        for (let num of nums) {
            this.add(num);
        }
    }

    // Adds a new number and returns the k-th largest
    add(val) {
        // Push value
        this.minHeap.push(val);

        // Sort to simulate heap behavior
        this.minHeap.sort((a, b) => a - b);

        // Remove smallest if size > k
        if (this.minHeap.length > this.k) {
            this.minHeap.shift();
        }

        // Return k-th largest
        return this.minHeap[0];
    }
}

